import { useEffect, useState } from "react"
import API from "../services/api"

export default function Jobs() {

    const [job, setJob] = useState(null)

    useEffect(() => {

        const fetchRecommendation = async () => {

            try {

                const token = localStorage.getItem("token")

                const res = await API.get(
                    "/jobs/recommend",
                    {
                        headers: {
                            Authorization: `Bearer ${token}`
                        }
                    }
                )

                setJob(res.data)

            } catch (error) {

                console.log(error)
            }
        }

        fetchRecommendation()

    }, [])

    const handleSaveJob = async () => {

        try {

            const token = localStorage.getItem("token")

            await API.post(
                "/jobs/save",
                {
                    role: job.recommendedRole
                },
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            )

            alert("Job saved!")

        } catch (error) {

            console.log(error)
        }
    }

    return (

        <div
            style={{
                padding: "30px",
                background: "#f4f4f4",
                minHeight: "100vh"
            }}
        >

            <h1
                style={{
                    marginBottom: "25px",
                    color: "#222"
                }}
            >
                Recommended Career Role
            </h1>

            {
                job ? (

                    <div
                        style={{
                            background: "white",
                            borderRadius: "15px",
                            padding: "25px",
                            maxWidth: "500px",
                            boxShadow:
                                "0 4px 12px rgba(0,0,0,0.1)"
                        }}
                    >

                        <h2
                            style={{
                                color: "#4CAF50",
                                marginBottom: "15px"
                            }}
                        >
                            {job.recommendedRole}
                        </h2>

                        <p
                            style={{
                                fontSize: "18px"
                            }}
                        >
                            <strong>Match Score:</strong>{" "}
                            {job.matchScore}
                        </p>

                        <button
                            onClick={handleSaveJob}
                            style={{
                                marginTop: "20px",
                                padding: "10px 18px",
                                border: "none",
                                backgroundColor: "#4CAF50",
                                color: "white",
                                borderRadius: "8px",
                                cursor: "pointer",
                                fontSize: "15px"
                            }}
                        >
                            Save Job
                        </button>

                    </div>

                ) : (

                    <p>Loading recommendation...</p>

                )
            }

        </div>
    )
}
